import type { CreateTimelineSection } from '@lib/animations/section-timeline';
import { interpolate } from '@utils/animations';

export type Section4Deps = {};

function getElements() {
  const section = document.getElementById('section4');
  const subtitle = document.getElementById('section4Subtitle');
  const left = document.getElementById('benefitImagesLeft');
  const right = document.getElementById('benefitImagesRight');
  if (!section) throw new Error('Section 1 not found');
  if (!subtitle) throw new Error('Section 4 subtitle not found');
  if (!left) throw new Error('Benefit images left not found');
  if (!right) throw new Error('Benefit images right not found');
  const images: HTMLElement[] = [];
  left.querySelectorAll('img').forEach(img => {
    images.push(img);
  });
  right.querySelectorAll('img').forEach(img => {
    images.push(img);
  });
  return { section, subtitle, images };
}

export const createSection4: CreateTimelineSection<Section4Deps> = libs => {
  const elements = getElements();
  return {
    id: 'section-4',
    section: elements.section,
    animations: [
      {
        id: 'parallax-benefit-images',
        start: 0,
        end: 100,
        update: progress => {
          const vh = window.innerHeight;
          for (let i = 0; i < elements.images.length; i++) {
            const isEven = (i + 1) % 2 === 0;
            const fromY = isEven ? vh * 0.5 : vh * 0;
            const toY = isEven ? vh * -0.2 : vh * -0.5;
            const y = interpolate(fromY, toY, progress);
            libs.gsap.set(elements.images[i], { y, opacity: progress });
          }
        }
      }
    ]
  };
};
