import { calculateCardFanPosition, initValuesCardFan } from '@features/careers/components/values-animation';
import type { CreateTimelineSection } from '@lib/animations/section-timeline';

export type Section3Deps = {};

function getElements() {
  const section = document.getElementById('section3');
  const header = document.getElementById('header3');
  const title = document.getElementById('header3Title');
  const label = document.getElementById('header3Label');
  const subtitle = document.getElementById('header3Subtitle');
  if (!section) throw new Error('Section 1 not found');
  if (!header) throw new Error('Header 3 not found');
  if (!title) throw new Error('Title 3 not found');
  if (!label) throw new Error('Label 3 not found');
  if (!subtitle) throw new Error('Subtitle 3 not found');
  return { section, header, title, label, subtitle };
}

export const createSection3: CreateTimelineSection<Section3Deps> = libs => {
  const elements = getElements();
  const valuesContainer = document.getElementById('valuesContainer');
  if (!valuesContainer) throw new Error('Values container not found');
  const values = valuesContainer.querySelectorAll('.value');
  if (values.length === 0) throw new Error('No values found');

  const titleSplit = libs.SplitText.create(elements.title, { type: 'words,chars' });
  titleSplit.chars.forEach(char => {
    libs.gsap.set(char, { opacity: 0.2 });
  });

  let hasAnimatedValues = false;
  let valuesTween: ReturnType<typeof libs.gsap.to> | null = null;
  let cardFanInitialized = false;
  // biome-ignore lint/correctness/noUnusedVariables: reason
  let cardFanInstance: ReturnType<typeof initValuesCardFan> | null = null;
  const VALUES_PLAY_AT = 0.15;

  const hideValues = () => {
    values.forEach((card, index) => {
      libs.gsap.set(card, {
        opacity: 1,
        scale: 0.92,
        rotation: 0,
        x: 0,
        y: 0,
        zIndex: values.length - index
      });
      const valueContent = card.querySelector('.valueContent');
      if (!valueContent) return;
      // Keep all content visible at opacity 1
      libs.gsap.set(valueContent, { opacity: 1 });
    });
  };

  hideValues();
  return {
    id: 'section-3',
    section: elements.section,
    animations: [
      {
        id: 'type-header-3',
        start: 20,
        end: 45,
        update: progress => {
          const totalChars = titleSplit.chars.length;
          const visibleChars = Math.ceil(progress * totalChars);
          titleSplit.chars.forEach((char, index) => {
            const opacity = index < visibleChars ? 1 : 0.2;
            libs.gsap.set(char, { opacity, y: 0 });
          });
        }
      },
      {
        id: 'animate-values',
        start: 50,
        end: 70,
        update: progress => {
          if (hasAnimatedValues || progress < VALUES_PLAY_AT) return;
          valuesTween?.kill();
          valuesTween = null;
          const totalCards = values.length;
          values.forEach((card, index) => {
            const targetPosition = calculateCardFanPosition(index, totalCards);
            libs.gsap.to(card, {
              opacity: 1,
              scale: targetPosition.scale,
              rotation: targetPosition.rotation,
              x: targetPosition.x,
              y: targetPosition.y,
              zIndex: targetPosition.zIndex,
              duration: 0.8,
              delay: index * 0.1,
              ease: 'power2.out'
            });
          });
          if (!cardFanInitialized) {
            const timeout = 800 + (totalCards - 1) * 100;
            setTimeout(() => {
              cardFanInstance = initValuesCardFan('valuesContainer');
              cardFanInitialized = true;
            }, timeout);
          }
          hasAnimatedValues = true;
        }
      }
    ]
  };
};
