import type { AnimationLibs } from '@lib/animations/animation-libs';
import { createHeaderFadeOutAnimation } from '@lib/animations/header-animations';
import type { CreateTimelineSection } from '@lib/animations/section-timeline';

export type Section1Deps = {};

function getElements(libs: AnimationLibs) {
  const section = document.getElementById('section1');
  const header = document.getElementById('header1');
  const title = document.getElementById('header1Title');
  const about = document.getElementById('header1Description');
  const link = document.getElementById('header1GetInTouchButton');
  if (!section) throw new Error('Section 1 not found');
  if (!header) throw new Error('Header 1 not found');
  if (!title) throw new Error('Title 1 not found');
  if (!about) throw new Error('About 1 not found');
  if (!link) throw new Error('Link 1 not found');
  return {
    section,
    header,
    title,
    titleSplit: libs.SplitText.create(title, { type: 'words,chars', aria: 'none' }),
    about,
    aboutSplit: libs.SplitText.create(about, { type: 'lines', aria: 'none' }),
    link
  };
}

export function fadeInHeader1(libs: AnimationLibs) {
  const elements = getElements(libs);
  const vh = window.innerHeight;
  libs.gsap.set(elements.title, { opacity: 1 });
  libs.gsap.set(elements.titleSplit.chars, { opacity: 0.01, filter: 'blur(8px)' });
  libs.gsap.to(elements.header, { opacity: 1 });
  libs.gsap.to(elements.titleSplit.chars, {
    opacity: 1,
    filter: 'blur(0px)',
    duration: 0.5,
    ease: 'power2.out',
    stagger: 0.05
  });
  libs.gsap.fromTo(
    elements.about,
    { opacity: 0, y: vh * 0.1 },
    {
      opacity: 1,
      y: 0,
      duration: 0.8,
      delay: 0.2,
      ease: 'power2.out'
    }
  );
  libs.gsap.fromTo(
    elements.link,
    { opacity: 0, y: vh * 0.1 },
    {
      opacity: 1,
      y: 0,
      duration: 0.8,
      delay: 0.6,
      ease: 'power2.out'
    }
  );
}

export const createSection1: CreateTimelineSection<Section1Deps> = libs => {
  const elements = getElements(libs);
  const fadeOutHeader = createHeaderFadeOutAnimation(1, libs);
  if (!fadeOutHeader) throw new Error('Failed to create header 1 fade out animation.');
  return {
    id: 'section-1',
    section: elements.section,
    start: 'top',
    animations: [
      {
        id: 'fade-out-header',
        start: 0,
        end: 15,
        update: progress => {
          const vh = window.innerHeight;
          fadeOutHeader(progress, { y: p => p * vh * 0.1 });
        }
      }
    ]
  };
};
