import type { AnimationLibs } from '@lib/animations/animation-libs';
import type { CreateTimelineSection } from '@lib/animations/section-timeline';
import { createSequentialThresholdAnimations } from '@lib/animations/text-animations';

export type Section2Deps = {};

function getElements(libs: AnimationLibs) {
  const section = document.getElementById('section2');
  const header = document.getElementById('header2');
  const title = document.getElementById('header2Title');
  const about = document.getElementById('header2Description');
  const video = document.getElementById('section2Video');
  if (!section) throw new Error('Section 2 not found');
  if (!header) throw new Error('Header 2 not found');
  if (!title) throw new Error('Title 2 not found');
  if (!about) throw new Error('About 2 not found');
  if (!video) throw new Error('Video 2 not found');
  return {
    section,
    header,
    title,
    titleSplit: libs.SplitText.create(title, { type: 'words,chars', aria: 'none' }),
    about,
    aboutSplit: libs.SplitText.create(about, { type: 'lines', aria: 'none' }),
    video
  };
}

export const createSection2: CreateTimelineSection<Section2Deps> = libs => {
  const elements = getElements(libs);
  const animateText = createSequentialThresholdAnimations(libs, [
    { elements: elements.titleSplit.chars },
    { elements: elements.aboutSplit.lines, startY: 0.04, overlap: 0.25, stagger: 0.1 }
  ]);

  return {
    id: 'section-2',
    section: elements.section,
    animations: [
      {
        id: 'animateText',
        start: 20,
        end: 30,
        update: animateText
      },
      {
        id: 'fade-in-video',
        start: 10,
        end: 30,
        update: progress => {
          libs.gsap.set(elements.video, { opacity: progress * 0.5 });
        }
      },
      {
        id: 'fade-out-video',
        start: 70,
        end: 90,
        update: progress => {
          libs.gsap.set(elements.video, { opacity: (1 - progress) * 0.5 });
        }
      }
    ]
  };
};
