import type { AnimationLibs } from './animation-libs';

export type AnimateHeaderInput = {
  index: number;
  libs: AnimationLibs;
  getY?: (progress: number) => number;
  getOpacity?: (progress: number) => number;
};

export type HeaderAnimationConfig = {
  y?: (progress: number) => number;
  opacity?: (progress: number) => number;
};

export type HeaderAnimation = (progress: number, config?: HeaderAnimationConfig) => void;

function getHeaderElements(index: number) {
  const headerId = `header${index}`;
  const headerTitleId = `header${index}Title`;
  const headerDescriptionId = `header${index}Description`;
  const header = document.getElementById(headerId);
  const headerTitle = document.getElementById(headerTitleId);
  const headerDescription = document.getElementById(headerDescriptionId);
  if (!header || !headerTitle || !headerDescription) return;
  return { header, headerTitle, headerDescription };
}

export function createHeaderFadeOutAnimation(index: number, libs: AnimationLibs): HeaderAnimation | null {
  const elements = getHeaderElements(index);
  if (!elements) return null;
  return (progress, config) => {
    const opacity = config?.opacity ? config.opacity(progress) : 1 - progress;
    const vh = window.innerHeight;
    const y = config?.y ? config.y(progress) : -vh * 0.1 * progress;
    libs.gsap.set(elements.header, {
      opacity,
      y,
      pointerEvents: opacity <= 0.01 ? 'none' : 'auto'
    });
  };
}

export function createHeaderFadeInAnimation(index: number, libs: AnimationLibs): HeaderAnimation | null {
  const elements = getHeaderElements(index);
  if (!elements) return null;
  const headerTitleSplit = libs.SplitText.create(elements.headerTitle, { type: 'words,chars' });
  let hasAnimatedHeaderTitleCharacters = false;
  libs.gsap.set(headerTitleSplit.chars, { opacity: 0 });
  return (progress, config) => {
    const opacity = config?.opacity ? config.opacity(progress) : progress;
    const y = config?.y ? config.y(progress) : 200 * (1 - progress);
    libs.gsap.set(elements.header, { opacity, y });
    if (!hasAnimatedHeaderTitleCharacters) {
      libs.gsap.set(elements.headerTitle, { opacity: 1 });
      libs.gsap.set(headerTitleSplit.chars, { opacity: 0 });
      libs.gsap.to(headerTitleSplit.chars, {
        opacity: 1,
        ease: 'power2.out',
        duration: 0.6,
        stagger: 0.02
      });
      libs.gsap.to(elements.headerDescription, { opacity: 1, duration: 1, delay: 0.6 });
      hasAnimatedHeaderTitleCharacters = true;
    } else if (progress < 0.1) {
      libs.gsap.set(headerTitleSplit.chars, { opacity: 0 });
      libs.gsap.set(elements.headerDescription, { opacity: 0 });
      hasAnimatedHeaderTitleCharacters = false;
    }
  };
}

export function createTitleFadeInAnimation(title: HTMLElement, libs: AnimationLibs): HeaderAnimation | null {
  const headerTitleSplit = libs.SplitText.create(title, { type: 'words,chars' });
  libs.gsap.set(headerTitleSplit.chars, { opacity: 0 });
  return (progress, config) => {
    const vh = window.innerHeight;
    const opacity = config?.opacity ? config.opacity(progress) : progress;
    const y = config?.y ? config.y(progress) : vh * 0.1 * (1 - progress);
    libs.gsap.set(headerTitleSplit.chars, {
      opacity,
      y,
      stagger: 0.02,
      duration: 0.6,
      ease: 'power2.out'
    });
  };
}

export function createFadeInHeaderAnimation(
  elements: { header: HTMLElement; title: HTMLElement; description?: HTMLElement },
  libs: AnimationLibs
): HeaderAnimation | null {
  const titleSplit = libs.SplitText.create(elements.title, { type: 'words,chars' });
  let hasAnimatedHeaderTitleCharacters = false;
  libs.gsap.set(titleSplit.chars, { opacity: 0 });
  return (progress, config) => {
    const opacity = config?.opacity ? config.opacity(progress) : progress;
    const vh = window.innerHeight;
    const y = config?.y ? config.y(progress) : vh * 0.1 * (1 - progress);
    libs.gsap.set(elements.header, { opacity, y });
    if (!hasAnimatedHeaderTitleCharacters) {
      libs.gsap.set(elements.title, { opacity: 1 });
      libs.gsap.set(titleSplit.chars, { opacity: 0 });
      libs.gsap.to(titleSplit.chars, {
        opacity: 1,
        ease: 'power2.out',
        duration: 0.6,
        stagger: 0.02
      });
      if (elements.description) libs.gsap.to(elements.description, { opacity: 1, duration: 1, delay: 0.6 });
      hasAnimatedHeaderTitleCharacters = true;
    } else if (progress < 0.1) {
      libs.gsap.set(titleSplit.chars, { opacity: 0 });
      if (elements.description) libs.gsap.set(elements.description, { opacity: 0 });
      hasAnimatedHeaderTitleCharacters = false;
    }
  };
}
