import type { CreateTimelineSection } from '@lib/animations/section-timeline';

export type Section5Deps = {};

function getElements() {
  const section = document.getElementById('section5');
  const footerTitle = document.getElementById('section5FooterTitle');
  const footerDescription = document.getElementById('section5FooterDescription');
  if (!section) throw new Error('Section 5 not found');
  if (!footerTitle) throw new Error('Section 5 footer title not found');
  if (!footerDescription) throw new Error('Section 5 footer description not found');
  return { section, footerTitle, footerDescription };
}

export const createSection5: CreateTimelineSection<Section5Deps> = libs => {
  const elements = getElements();
  const footerTitleSplit = libs.SplitText.create(elements.footerTitle, { type: 'words,chars' });
  let hasAnimatedFooter = false;
  let titleTween: ReturnType<typeof libs.gsap.to> | null = null;
  let descriptionTween: ReturnType<typeof libs.gsap.to> | null = null;
  const FOOTER_RESET_AT = 0.02;
  const FOOTER_PLAY_AT = 0.15;
  const footerDescriptionSplit = libs.SplitText.create(elements.footerDescription, {
    type: 'lines',
    aria: 'none'
  });

  const hideFooter = () => {
    // Keep layout stable while hiding characters/lines.
    libs.gsap.set(elements.footerTitle, { opacity: 1 });
    libs.gsap.set(footerTitleSplit.chars, { opacity: 0 });
    libs.gsap.set(elements.footerDescription, { opacity: 1 });
    libs.gsap.set(footerDescriptionSplit.lines, { opacity: 0 });
  };

  // Ensure we never "flash" visible before the first scroll-driven update runs.
  hideFooter();

  return {
    id: 'section-5',
    section: elements.section,
    animations: [
      {
        id: 'fade-in-footer',
        start: 40,
        end: 60,
        update: progress => {
          // Timeline calls `update(0)` when you're above the range and `update(1)` when you're below it.
          // We must not auto-play at progress=0, otherwise scrolling back up will re-trigger and flicker.
          if (progress <= FOOTER_RESET_AT) {
            if (!hasAnimatedFooter && !titleTween && !descriptionTween) return;
            titleTween?.kill();
            descriptionTween?.kill();
            titleTween = null;
            descriptionTween = null;
            hideFooter();
            hasAnimatedFooter = false;
            return;
          }

          if (!hasAnimatedFooter && progress >= FOOTER_PLAY_AT) {
            titleTween?.kill();
            descriptionTween?.kill();
            titleTween = null;
            descriptionTween = null;
            hideFooter();

            titleTween = libs.gsap.to(footerTitleSplit.chars, {
              opacity: 1,
              ease: 'power2.out',
              duration: 0.6,
              stagger: 0.02
            });
            descriptionTween = libs.gsap.to(footerDescriptionSplit.lines, {
              opacity: 1,
              ease: 'power2.out',
              duration: 0.6,
              stagger: 0.08,
              delay: 0.6
            });
            hasAnimatedFooter = true;
          }
        }
      }
    ]
  };
};
