import { gsap } from 'gsap';

interface CardState {
  scale: number;
  rotation: number;
  y: number;
  x: number;
  zIndex: number;
}

export class ValuesCardFan {
  private container: HTMLElement;
  private cards: HTMLElement[];
  private cardContents: HTMLElement[];
  private leftButton: HTMLButtonElement;
  private rightButton: HTMLButtonElement;
  private currentIndex: number = 0;
  private isAnimating: boolean = false;
  private totalCards: number;

  // Drag state
  private isDragging: boolean = false;
  private dragStartX: number = 0;
  private dragStartY: number = 0;
  private currentDragX: number = 0;
  private dragStartTime: number = 0;
  private velocityX: number = 0;

  constructor(containerId: string) {
    const wrapper = document.getElementById(containerId);
    if (!wrapper) throw new Error(`Values wrapper with id "${containerId}" not found`);

    const container = wrapper.querySelector('.values') as HTMLElement;
    if (!container) throw new Error('Values container not found');

    const leftButton = wrapper.querySelector('.arrowLeft') as HTMLButtonElement;
    const rightButton = wrapper.querySelector('.arrowRight') as HTMLButtonElement;
    if (!leftButton || !rightButton) throw new Error('Navigation buttons not found');

    this.container = container;
    this.cards = Array.from(container.querySelectorAll('.value'));
    this.cardContents = Array.from(container.querySelectorAll('.valueContent'));
    this.leftButton = leftButton;
    this.rightButton = rightButton;
    this.totalCards = this.cards.length;

    this.init();
  }

  private init(): void {
    // Set initial positions for all cards (they will be faded in by the scroll animation)
    this.cards.forEach((card, index) => {
      const position = this.calculateCardPosition(index);
      gsap.set(card, {
        scale: position.scale,
        rotation: position.rotation,
        y: position.y,
        x: position.x,
        zIndex: position.zIndex
        // Don't set opacity here - let the scroll animation handle it
      });
    });

    // Set initial content opacity - all cards visible
    this.cardContents.forEach(content => {
      gsap.set(content, {
        opacity: 1
      });
    });

    // Setup event listeners
    this.leftButton.addEventListener('click', () => this.handleLeftClick());
    this.rightButton.addEventListener('click', () => this.handleRightClick());

    // Setup drag event listeners
    this.setupDragListeners();

    // Update button states
    this.updateButtonStates();
  }

  private calculateCardPosition(index: number): CardState {
    const relativeIndex = index - this.currentIndex;
    const zIndex = this.totalCards - index;

    // Cards that have been dismissed (negative index) should be off-screen to the left
    if (relativeIndex < 0) {
      return {
        scale: 0.9,
        rotation: 0,
        y: 0,
        x: -200,
        zIndex
      };
    }

    // Visible cards in the fan - increased x offset for better visibility
    return {
      scale: 1 - relativeIndex * 0.08,
      rotation: relativeIndex * 5,
      y: relativeIndex * 0,
      x: relativeIndex * 25, // Increased from 8 to 50 for visible fan effect
      zIndex
    };
  }

  private calculateCardPositionWithRelativeIndex(index: number, relativeIndex: number): CardState {
    const zIndex = this.totalCards - index;

    // Cards that have been dismissed (negative index) should be off-screen to the left
    if (relativeIndex < 0) {
      return {
        scale: 0.9,
        rotation: 0,
        y: 0,
        x: -200,
        zIndex
      };
    }

    return {
      scale: 1 - relativeIndex * 0.08,
      rotation: relativeIndex * 5,
      y: relativeIndex * 0,
      x: relativeIndex * 40,
      zIndex
    };
  }

  private handleRightClick(): void {
    if (this.isAnimating) return;

    // Check if we have more than 1 card visible
    const remainingCards = this.totalCards - this.currentIndex;
    if (remainingCards <= 1) return;

    this.isAnimating = true;
    const timeline = gsap.timeline({
      onComplete: () => {
        this.currentIndex++;
        this.updateButtonStates();
        this.isAnimating = false;
      }
    });

    // Animate the front card out
    const frontCard = this.cards[this.currentIndex];
    timeline.to(
      frontCard,
      {
        x: -200,
        opacity: 0,
        duration: 0.6,
        ease: 'power2.inOut'
      },
      0
    );

    // Keep front card content visible (no fade)

    // Animate all remaining cards to their new positions
    for (let i = this.currentIndex + 1; i < this.totalCards; i++) {
      const card = this.cards[i];
      const newRelativeIndex = i - this.currentIndex - 1;
      const newPosition = this.calculateCardPositionWithRelativeIndex(i, newRelativeIndex);

      timeline.to(
        card,
        {
          scale: newPosition.scale,
          rotation: newPosition.rotation,
          y: newPosition.y,
          x: newPosition.x,
          zIndex: newPosition.zIndex,
          duration: 0.6,
          ease: 'power2.inOut'
        },
        0
      );

      // Content stays at opacity 1
    }
  }

  private handleLeftClick(): void {
    if (this.isAnimating) return;
    if (this.currentIndex === 0) return;

    this.isAnimating = true;
    this.currentIndex--;

    const timeline = gsap.timeline({
      onComplete: () => {
        this.updateButtonStates();
        this.isAnimating = false;
      }
    });

    // Keep all content visible (no fade)

    // Bring back the previous front card
    const previousCard = this.cards[this.currentIndex];
    const frontPosition = this.calculateCardPosition(this.currentIndex);

    timeline.to(
      previousCard,
      {
        x: frontPosition.x,
        opacity: 1,
        scale: frontPosition.scale,
        rotation: frontPosition.rotation,
        y: frontPosition.y,
        zIndex: frontPosition.zIndex,
        duration: 0.6,
        ease: 'power2.inOut'
      },
      0
    );

    // Content stays at opacity 1

    // Shift all other visible cards back
    for (let i = this.currentIndex + 1; i < this.totalCards; i++) {
      const card = this.cards[i];
      const newPosition = this.calculateCardPosition(i);

      timeline.to(
        card,
        {
          scale: newPosition.scale,
          rotation: newPosition.rotation,
          y: newPosition.y,
          x: newPosition.x,
          zIndex: newPosition.zIndex,
          duration: 0.6,
          ease: 'power2.inOut'
        },
        0
      );
    }
  }

  private updateButtonStates(): void {
    // Left button disabled at start
    this.leftButton.disabled = this.currentIndex === 0;

    // Right button disabled when only 1 card remains
    const remainingCards = this.totalCards - this.currentIndex;
    this.rightButton.disabled = remainingCards <= 1;
  }

  private setupDragListeners(): void {
    // Mouse events
    this.container.addEventListener('mousedown', e => this.handleDragStart(e));
    document.addEventListener('mousemove', e => this.handleDragMove(e));
    document.addEventListener('mouseup', () => this.handleDragEnd());

    // Touch events
    this.container.addEventListener('touchstart', e => this.handleDragStart(e), {
      passive: true
    });
    document.addEventListener('touchmove', e => this.handleDragMove(e), { passive: true });
    document.addEventListener('touchend', () => this.handleDragEnd());

    // Prevent default drag behavior
    this.container.addEventListener('dragstart', e => e.preventDefault());
  }

  private handleDragStart(e: MouseEvent | TouchEvent): void {
    if (this.isAnimating) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    this.isDragging = true;
    this.dragStartX = clientX;
    this.dragStartY = clientY;
    this.currentDragX = 0;
    this.dragStartTime = Date.now();
    this.velocityX = 0;

    // Add dragging class for cursor feedback
    this.container.style.cursor = 'grabbing';
  }

  private handleDragMove(e: MouseEvent | TouchEvent): void {
    if (!this.isDragging || this.isAnimating) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    const deltaX = clientX - this.dragStartX;
    const deltaY = clientY - this.dragStartY;

    // If dragging more vertically than horizontally, don't interfere with scrolling
    if (Math.abs(deltaY) > Math.abs(deltaX)) {
      return;
    }

    this.currentDragX = deltaX;

    // Calculate velocity for momentum
    const deltaTime = Date.now() - this.dragStartTime;
    this.velocityX = deltaX / deltaTime;

    // Apply drag to the current front card
    const frontCard = this.cards[this.currentIndex];
    if (frontCard) {
      const basePosition = this.calculateCardPosition(this.currentIndex);
      const dragProgress = Math.max(-1, Math.min(1, deltaX / 200)); // Normalize to -1 to 1

      gsap.to(frontCard, {
        x: basePosition.x + deltaX,
        rotation: basePosition.rotation + dragProgress * 10, // Add slight rotation during drag
        duration: 0.1,
        ease: 'none'
      });

      // Keep all visible card content at full opacity
      const frontCardContent = this.cardContents[this.currentIndex];
      gsap.to(frontCardContent, {
        opacity: 1,
        duration: 0.1,
        ease: 'none'
      });

      // Keep next card content visible (if exists)
      if (this.currentIndex + 1 < this.totalCards) {
        const nextCardContent = this.cardContents[this.currentIndex + 1];
        gsap.to(nextCardContent, {
          opacity: 1,
          duration: 0.1,
          ease: 'none'
        });
      }

      // Keep previous card content visible when dragging right (if exists)
      if (deltaX > 0 && this.currentIndex > 0) {
        const prevCardContent = this.cardContents[this.currentIndex - 1];
        gsap.to(prevCardContent, {
          opacity: 1,
          duration: 0.1,
          ease: 'none'
        });
      }
    }
  }

  private handleDragEnd(): void {
    if (!this.isDragging) return;

    this.isDragging = false;
    this.container.style.cursor = 'grab';

    const dragThreshold = 80; // Minimum drag distance to trigger navigation
    const velocityThreshold = 0.5; // Minimum velocity for momentum swipe

    // Determine if we should navigate based on drag distance or velocity
    const shouldNavigateRight = this.currentDragX < -dragThreshold || this.velocityX < -velocityThreshold;
    const shouldNavigateLeft = this.currentDragX > dragThreshold || this.velocityX > velocityThreshold;

    // Check if navigation is possible
    const canGoRight = this.totalCards - this.currentIndex > 1;
    const canGoLeft = this.currentIndex > 0;

    if (shouldNavigateRight && canGoRight) {
      // Swipe left = go to next card (right button)
      this.handleRightClick();
    } else if (shouldNavigateLeft && canGoLeft) {
      // Swipe right = go to previous card (left button)
      this.handleLeftClick();
    } else {
      // Snap back to original position
      const frontCard = this.cards[this.currentIndex];
      const frontCardContent = this.cardContents[this.currentIndex];
      const basePosition = this.calculateCardPosition(this.currentIndex);

      gsap.to(frontCard, {
        x: basePosition.x,
        rotation: basePosition.rotation,
        duration: 0.4,
        ease: 'power2.out'
      });

      gsap.to(frontCardContent, {
        opacity: 1,
        duration: 0.3,
        ease: 'power2.out'
      });

      // Keep all visible card content at opacity 1 (no reset needed)
    }

    this.currentDragX = 0;
  }

  public destroy(): void {
    this.leftButton.removeEventListener('click', () => this.handleLeftClick());
    this.rightButton.removeEventListener('click', () => this.handleRightClick());

    // Remove drag listeners
    this.container.removeEventListener('mousedown', e => this.handleDragStart(e));
    document.removeEventListener('mousemove', e => this.handleDragMove(e));
    document.removeEventListener('mouseup', () => this.handleDragEnd());
    this.container.removeEventListener('touchstart', e => this.handleDragStart(e));
    document.removeEventListener('touchmove', e => this.handleDragMove(e));
    document.removeEventListener('touchend', () => this.handleDragEnd());
  }
}

export function initValuesCardFan(containerId: string): ValuesCardFan {
  return new ValuesCardFan(containerId);
}

// Export helper function for calculating card positions
export function calculateCardFanPosition(index: number, totalCards: number): CardState {
  return {
    scale: 1 - index * 0.08,
    rotation: index * 5,
    y: index * 0,
    x: index * 25,
    zIndex: totalCards - index
  };
}
